package com.radiacode.shared.core.device.connection

import com.juul.kable.Peripheral
import com.juul.kable.State
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.distinctUntilChanged
import kotlinx.coroutines.flow.map

/**
 * Состояние BLE-соединения.
 */
enum class ConnectionState {
    Disconnected, Connecting, Connected, Disconnecting
}

/**
 * Живое BLE-соединение: одноразовое, умирает вместе с линком.
 */
interface DeviceConnection {

    /** Состояние соединения. */
    val state: Flow<ConnectionState>

    /** Канал обмена. */
    val transport: DeviceTransport

    /** Текущий RSSI соединения в dBm. */
    suspend fun rssi(): Int

    /** Разрывает соединение. */
    suspend fun disconnect()
}

/**
 * Реализация [DeviceConnection] поверх живой периферии Kable.
 */
internal class KableDeviceConnection(
    private val peripheral: Peripheral,
) : DeviceConnection {

    override val state: Flow<ConnectionState> =
        peripheral.state.map { it.toConnectionState() }.distinctUntilChanged()

    override val transport: DeviceTransport = KableDeviceTransport(peripheral)

    override suspend fun rssi(): Int = peripheral.rssi()

    override suspend fun disconnect() {
        try {
            peripheral.disconnect()
        } finally {
            peripheral.close()
        }
    }
}

internal fun State.toConnectionState(): ConnectionState = when (this) {
    is State.Connecting -> ConnectionState.Connecting
    is State.Connected -> ConnectionState.Connected
    is State.Disconnecting -> ConnectionState.Disconnecting
    is State.Disconnected -> ConnectionState.Disconnected
}

package com.radiacode.shared.core.device.connection

/** Не удалось подготовить соединение с прибором. */
class DeviceConnectionException(message: String) : Exception(message)

/**
 * Создаёт соединения с приборами.
 */
interface DeviceConnector {

    /**
     * Новый экземпляр живого соединения с периферией [peripheralId].
     *
     * @throws DeviceConnectionException если у прибора нет сервиса RadiaCode или нужных характеристик
     */
    suspend fun connect(peripheralId: String): DeviceConnection
}

/**
 * Реализация [DeviceConnector] поверх Kable.
 */
internal class KableDeviceConnector : DeviceConnector {

    override suspend fun connect(peripheralId: String): DeviceConnection {
        val peripheral = peripheralFrom(peripheralId)
        try {
            peripheral.connect()
            return KableDeviceConnection(peripheral)
        } catch (cause: Throwable) {
            peripheral.close()
            throw cause
        }
    }
}

package com.radiacode.shared.core.device.connection

import com.juul.kable.Characteristic
import com.juul.kable.Peripheral
import com.juul.kable.WriteType
import com.juul.kable.notify
import com.juul.kable.write
import com.radiacode.shared.core.device.scan.RadiacodeBLEParams
import kotlinx.coroutines.flow.Flow

/**
 * Байтовый обмен с подключённым прибором. Живёт, пока живо породившее его соединение.
 */
interface DeviceTransport {

    /** Пакеты, которые присылает прибор. Подписка активна, пока поток собирается. */
    val notifications: Flow<ByteArray>

    /** Пишет один пакет и ждёт подтверждения доставки. */
    suspend fun write(packet: ByteArray)
}

/**
 * Реализация [DeviceTransport] поверх подключённой периферии Kable:
 * сама находит свои write/notify-характеристики у прибора.
 * Создаётся соединением после `connect()`.
 */
internal class KableDeviceTransport(
    private val peripheral: Peripheral,
) : DeviceTransport {

    private val writeCharacteristic: Characteristic
    private val notifyCharacteristic: Characteristic

    init {
        val service = peripheral.services.value.orEmpty()
            .firstOrNull { it.serviceUuid == RadiacodeBLEParams.serviceUuid }
            ?: throw DeviceConnectionException("RadiaCode service not found on ${peripheral.identifier}")
        writeCharacteristic = service.characteristics.firstOrNull { it.properties.write }
            ?: throw DeviceConnectionException("Write characteristic not found on ${peripheral.identifier}")
        notifyCharacteristic = service.characteristics.firstOrNull { it.properties.notify }
            ?: throw DeviceConnectionException("Notify characteristic not found on ${peripheral.identifier}")
    }

    override val notifications: Flow<ByteArray> =
        peripheral.observe(notifyCharacteristic)

    override suspend fun write(packet: ByteArray) {
        peripheral.write(writeCharacteristic, packet, WriteType.WithResponse)
    }
}

package com.radiacode.shared.core.device.scan

import com.juul.kable.Scanner
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.mapNotNull

/**
 * Поиск приборов RadiaCode.
 */
interface DeviceScanner {

    /** Поток найденных устройств.*/
    fun scan(): Flow<RadiaCodeDiscovery>
}

/**
 * Реализация [DeviceScanner] поверх Kable.
 */
class KableDeviceScanner : DeviceScanner {

    private val scanner = Scanner {
        filters {
            match {
                services = listOf(RadiacodeBLEParams.serviceUuid)
            }
        }
    }

    override fun scan(): Flow<RadiaCodeDiscovery> =
        scanner.advertisements.mapNotNull { advertisement ->
            RadiaCodeDiscoveryParser.parse(
                name = advertisement.peripheralName,
                localName = advertisement.name,
                peripheralId = advertisement.identifier.toString(),
                rssi = advertisement.rssi,
            )
        }
}

package com.radiacode.shared.core.device.model

/**
 * Прибор RadiaCode
 */
class RadiaCodeDevice(
    val identifier: String,
    val model: RadiaCodeModel,
) {
    constructor(id: String, modelName: String) : this(id, RadiaCodeModel(modelName))

    override fun equals(other: Any?): Boolean =
        other is RadiaCodeDevice && other.identifier == identifier

    override fun hashCode(): Int = identifier.hashCode()

    companion object {
        fun serialNumber(serialNumber: String): RadiaCodeDevice? {
            val parts = serialNumber.split("-")
            if (parts.size < 3 || parts[0] != "RC") return null
            return RadiaCodeDevice(serialNumber, RadiaCodeModel.serialCode(parts[1]))
        }
    }
}

package com.radiacode.shared.core.device.model

/**
 * Находка скана — прибор RadiaCode, увиденный при BLE-сканировании.
 */
class RadiaCodeDiscovery(
    val device: RadiaCodeDevice,
    val signal: BluetoothSignal,
    val peripheralId: String,
) {
    /** Равенство — по [device] (то есть по его `identifier`): одно устройство в списке не двоится.*/
    override fun equals(other: Any?): Boolean =
        other is RadiaCodeDiscovery && other.device == device

    override fun hashCode(): Int = device.hashCode()
}

package com.radiacode.shared.core.device.model

/**
 * Семейство приборов RadiaCode
 */
enum class RadiaCodeFamily {
    RadiaCode10x, RadiaCode11x, RadiaCode103G, RadiaCode41x;

    /** Используется в именах ресурсных файлов (изотопы, контейнеры). */
    val postFix: String
        get() = when (this) {
            RadiaCode10x  -> "_10x"
            RadiaCode11x  -> "_11x"
            RadiaCode103G -> "_103G"
            RadiaCode41x  -> "_41x"
        }
}

package com.radiacode.shared.core.device.model

/**
 * Модель прибора RadiaCode
 *
 * [name] — каноническое имя: для файлов экспорта/импорта и хранения,
 * [invoke] разбирает его обратно. Для интерфейса — [displayName].
 */
sealed class RadiaCodeModel(val name: String) {
    data object RadiaCode101 : RadiaCodeModel("RadiaCode-101")
    data object RadiaCode102 : RadiaCodeModel("RadiaCode-102")
    data object RadiaCode103 : RadiaCodeModel("RadiaCode-103")
    data object RadiaCode103G : RadiaCodeModel("RadiaCode-103G")
    data object RadiaCode110 : RadiaCodeModel("RadiaCode-110")
    data object RadiaCodeZero : RadiaCodeModel("RadiaCode-Zero")
    data class Other(val rawName: String) : RadiaCodeModel(rawName)

    val family: RadiaCodeFamily
        get() = when (this) {
            RadiaCode101, RadiaCode102, RadiaCode103 -> RadiaCodeFamily.RadiaCode10x
            RadiaCode103G -> RadiaCodeFamily.RadiaCode103G
            RadiaCode110 -> RadiaCodeFamily.RadiaCode11x
            RadiaCodeZero -> RadiaCodeFamily.RadiaCode41x
            is Other -> when {
                rawName.startsWith("RadiaCode-10") -> RadiaCodeFamily.RadiaCode10x
                rawName.startsWith("RadiaCode-11") -> RadiaCodeFamily.RadiaCode11x
                rawName.startsWith("RadiaCode-41") -> RadiaCodeFamily.RadiaCode41x
                else -> RadiaCodeFamily.RadiaCode10x
            }
        }

    /** Имя модели для интерфейса. */
    val displayName: String = name.replace("RadiaCode", "Radiacode").replace("-", " ")

    companion object {
        /** Из любого варианта имени: эфирного, канонического [name] или отображаемого [displayName]. */
        operator fun invoke(rawValue: String): RadiaCodeModel {
            val canonical = rawValue
                .replace("Radiacode", "RadiaCode")
                .replace("RadiaCode ", "RadiaCode-")
            return when (canonical) {
                "RadiaCode-101" -> RadiaCode101
                "RadiaCode-102" -> RadiaCode102
                "RadiaCode-103" -> RadiaCode103
                "RadiaCode-103G" -> RadiaCode103G
                "RadiaCode-110" -> RadiaCode110
                "RadiaCode-Zero" -> RadiaCodeZero
                else -> Other(rawValue)
            }
        }

        /** Из серийного кода */
        fun serialCode(serialCode: String): RadiaCodeModel = when (serialCode) {
            "101" -> RadiaCode101
            "102" -> RadiaCode102
            "103" -> RadiaCode103
            "103G" -> RadiaCode103G
            "110" -> RadiaCode110
            "Zero", "410" -> RadiaCodeZero
            else -> Other("RadiaCode-$serialCode")
        }
    }
}

package com.radiacode.shared.core.device.model

/**
 * Enum для определения уровня BLE-сигнала. Может шариться между приложениями, но в
 * основном предназначен для явного вычисления качества сигнала от 0 (отсутствует) до 1 (максимальный).
 */
enum class BluetoothSignal {
    Strong, Good, Fair, Poor, NoSignal;

    /** 0…1 — заполнение индикатора «палочек». */
    val value: Double
        get() = when (this) {
            Strong   -> 1.0
            Good     -> 0.75
            Fair     -> 0.5
            Poor     -> 0.25
            NoSignal -> 0.0
        }

    companion object {
        /** Из RSSI (dBm). `null` (нет данных) или слишком слабый → [NoSignal]. */
        operator fun invoke(rssi: Int?): BluetoothSignal = when {
            rssi == null -> NoSignal
            rssi >= -60  -> Strong
            rssi >= -70  -> Good
            rssi >= -80  -> Fair
            rssi >= -90  -> Poor
            else         -> NoSignal
        }
    }
}

package com.radiacode.shared.core.storage

import com.radiacode.shared.core.device.model.BluetoothSignal
import com.radiacode.shared.core.device.model.RadiaCodeDevice
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery
import com.russhwolf.settings.Settings

/**
 * Хранилище прибора, с которым работало приложение, — для автоподключения в следующей сессии.
 */
interface DeviceStorage {

    /** Последний подключённый прибор; `null` — не сохранён. */
    var lastConnectedDevice: RadiaCodeDiscovery?
}

/**
 * Реализация [DeviceStorage] поверх multiplatform-settings.
 */
internal class SettingsDeviceStorage(private val settings: Settings) : DeviceStorage {

    override var lastConnectedDevice: RadiaCodeDiscovery?
        get() {
            val peripheralId = settings.getStringOrNull(KEY_PERIPHERAL_ID) ?: return null
            val identifier = settings.getStringOrNull(KEY_IDENTIFIER) ?: return null
            val modelName = settings.getStringOrNull(KEY_MODEL) ?: return null
            return RadiaCodeDiscovery(
                device = RadiaCodeDevice(identifier, modelName),
                signal = BluetoothSignal.NoSignal,
                peripheralId = peripheralId,
            )
        }
        set(value) {
            if (value == null) {
                settings.remove(KEY_PERIPHERAL_ID)
                settings.remove(KEY_IDENTIFIER)
                settings.remove(KEY_MODEL)
            } else {
                settings.putString(KEY_PERIPHERAL_ID, value.peripheralId)
                settings.putString(KEY_IDENTIFIER, value.device.identifier)
                settings.putString(KEY_MODEL, value.device.model.name)
            }
        }

    private companion object {
        const val KEY_PERIPHERAL_ID = "savedDevice.peripheralId"
        const val KEY_IDENTIFIER = "savedDevice.identifier"
        const val KEY_MODEL = "savedDevice.model"
    }
}

