@Composable
fun BatteryLevel(
    charge: Int?,
    onCharge: Boolean = false,
    lowBattery: Boolean = false,
    modifier: Modifier = Modifier,
    iconSize: Dp = 24.dp,
) {
    Row(
        modifier = modifier,
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(6.dp),
    ) {
        when {
            onCharge -> {
                Image(
                    painter = painterResource(R.drawable.ic_battery_charging),
                    contentDescription = "Battery charging",
                    modifier = Modifier.size(iconSize),
                )
            }

            charge != null -> {
                Image(
                    painter = painterResource(batteryDrawable(charge)),
                    contentDescription = "Battery charge is $charge%",
                    modifier = Modifier.size(iconSize),
                )
                Text(
                    text = "$charge%",
                    style = MaterialTheme.typography.labelLarge,
                    color = if (lowBattery) {
                        MaterialTheme.colorScheme.error
                    } else {
                        MaterialTheme.colorScheme.onSurface
                    },
                )
            }

            else -> {
                Image(
                    painter = painterResource(R.drawable.ic_battery_0),
                    contentDescription = "Battery charge unknown",
                    modifier = Modifier.size(iconSize),
                )
                Text(
                    text = "-- %",
                    style = MaterialTheme.typography.labelLarge,
                    color = MaterialTheme.colorScheme.onSurface,
                )
            }
        }
    }
}

@DrawableRes
private fun batteryDrawable(charge: Int): Int = when (charge.coerceIn(0, 100)) {
    in 0..5 -> R.drawable.ic_battery_0
    in 6..15 -> R.drawable.ic_battery_10
    in 16..25 -> R.drawable.ic_battery_20
    in 26..35 -> R.drawable.ic_battery_30
    in 36..50 -> R.drawable.ic_battery_40
    in 51..65 -> R.drawable.ic_battery_60
    in 66..75 -> R.drawable.ic_battery_70
    in 76..90 -> R.drawable.ic_battery_80
    else -> R.drawable.ic_battery_100
}

@Preview(showBackground = true, backgroundColor = 0xFF000000)
