        ) {
            BatteryLevel(charge = null)
            BatteryLevel(charge = 100, onCharge = true)
            BatteryLevel(charge = 100)
            BatteryLevel(charge = 72)
            BatteryLevel(charge = 45)
            BatteryLevel(charge = 10, lowBattery = true)
        }
    }
}

