@Composable
fun BluetoothStrength(
    signal: BluetoothSignal,
    modifier: Modifier = Modifier,
    iconSize: Dp = 24.dp,
) {
    // Если сигнала нет - то мы пока рисуем пустую иконку. Возможно, согласуем с бизнес-логикой и будем рисовать другую иконку
    val barsRes = when (signal) {
        BluetoothSignal.Strong, BluetoothSignal.Good -> R.drawable.ic_signal_cellular_alt_24px
        BluetoothSignal.Fair -> R.drawable.ic_signal_cellular_alt_2_bar_24px
        BluetoothSignal.Poor -> R.drawable.ic_signal_cellular_alt_1_bar_24px
        BluetoothSignal.NoSignal -> return
    }
    Row(
        modifier = modifier,
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(6.dp),
    ) {
        Icon(
            painter = painterResource(R.drawable.ic_bluetooth_24px),
            contentDescription = null,
            tint = MaterialTheme.colorScheme.primary,
            modifier = Modifier.size(iconSize),
        )
        Icon(
            painter = painterResource(barsRes),
            contentDescription = "Bluetooth signal: ${signal.name}",
            tint = MaterialTheme.colorScheme.onSurface,
            modifier = Modifier.size(iconSize),
        )
    }
}

