private fun Color.toHex(): String = "#%06X".format(0xFFFFFF and toArgb())

@Composable
private fun ColorSwatch(role: ColorRole, modifier: Modifier = Modifier) {
    Column(
        modifier = modifier
            .clip(RoundedCornerShape(16.dp))
            .background(role.color)
            .border(1.dp, MaterialTheme.colorScheme.outlineVariant, RoundedCornerShape(16.dp))
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(2.dp),
    ) {
        Text(role.name, style = MaterialTheme.typography.titleSmall, color = role.onColor)
        Text(role.color.toHex(), style = MaterialTheme.typography.bodySmall, color = role.onColor)
    }
}

@Composable
private fun ColorSwatchRow(left: ColorRole, right: ColorRole) {
    Row(
        modifier = Modifier.height(IntrinsicSize.Min),
        horizontalArrangement = Arrangement.spacedBy(8.dp),
    ) {
        ColorSwatch(left, Modifier.weight(1f).fillMaxHeight())
        ColorSwatch(right, Modifier.weight(1f).fillMaxHeight())
    }
}

@Composable
private fun PaletteRamp(name: String, tones: List<Color>) {
    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
        Text(name, style = MaterialTheme.typography.labelMedium, color = Palette.Neutral.tone90)
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .height(28.dp)
                .clip(RoundedCornerShape(8.dp))
                .border(1.dp, Palette.Neutral.tone80, RoundedCornerShape(8.dp)),
        ) {
            tones.forEach { tone ->
                Box(Modifier.weight(1f).fillMaxHeight().background(tone))
            }
        }
    }
}

/**
 * Общий компонент с превью всех цветов - от нейтральных, до основных + ошибки / success состояния
 * Синхронизирован со стандартной палеткой Material Theme, а также содержит пример прямого использования цвета
 * из палетки, если этого требует дизайн.
 * Использует [PaletteRamp], [ColorSwatchRow], [ColorSwatch] composables для превью
 */
@Preview(showBackground = true, backgroundColor = 0xFF000000, widthDp = 360)
@Composable
private fun ColorPreview() {
    AppTheme {
        val scheme = MaterialTheme.colorScheme
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .background(scheme.background)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp),
        ) {
            PaletteRamp(
                name = "Palette.Neutral · tone0 → tone100",
                tones = listOf(
                    Palette.Neutral.tone0, Palette.Neutral.tone5, Palette.Neutral.tone10,
                    Palette.Neutral.tone20, Palette.Neutral.tone25, Palette.Neutral.tone30,
                    Palette.Neutral.tone40, Palette.Neutral.tone50, Palette.Neutral.tone60,
                    Palette.Neutral.tone70, Palette.Neutral.tone80, Palette.Neutral.tone90,
                    Palette.Neutral.tone95, Palette.Neutral.tone99, Palette.Neutral.tone100,
                ),
            )
            ColorSwatchRow(
                ColorRole("Primary", scheme.primary, scheme.onPrimary),
                ColorRole("Primary Container", scheme.primaryContainer, scheme.onPrimaryContainer),
            )
            ColorSwatchRow(
                ColorRole("Secondary", scheme.secondary, scheme.onSecondary),
                ColorRole("Secondary Container", scheme.secondaryContainer, scheme.onSecondaryContainer),
            )
            ColorSwatchRow(
                ColorRole("Success", scheme.tertiary, scheme.onTertiary),
                ColorRole("Success Container", scheme.tertiaryContainer, scheme.onTertiaryContainer),
            )
            ColorSwatchRow(
                ColorRole("Error", scheme.error, scheme.onError),
                ColorRole("Error Container", scheme.errorContainer, scheme.onErrorContainer),
            )
            ColorSwatchRow(
                ColorRole("Surface", scheme.surface, scheme.onSurface),
                ColorRole("Surface Dim", scheme.surfaceDim, scheme.onSurface),
            )
            ColorSwatchRow(
                ColorRole("Container Lowest", scheme.surfaceContainerLowest, scheme.onSurface),
                ColorRole("Container Low", scheme.surfaceContainerLow, scheme.onSurface),
            )
            ColorSwatchRow(
                ColorRole("Container", scheme.surfaceContainer, scheme.onSurface),
                ColorRole("Container High", scheme.surfaceContainerHigh, scheme.onSurface),
            )
            ColorSwatchRow(
                ColorRole("Container Highest", scheme.surfaceContainerHighest, scheme.onSurface),
                ColorRole("Surface Bright", scheme.surfaceBright, scheme.onSurface),
            )
            ColorSwatchRow(
                ColorRole("Outline", scheme.outline, scheme.surface),
                ColorRole("Outline Variant", scheme.outlineVariant, scheme.onSurface),
            )
        }
    }
}

