package com.radiacode.shared.core.device.scan

import com.radiacode.shared.core.device.model.BluetoothSignal
import com.radiacode.shared.core.device.model.RadiaCodeDevice
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery

/**
 * Разбор найденного устройства в [RadiaCodeDiscovery].
 */
internal object RadiaCodeDiscoveryParser {

    /**
     * Разбирает находку: имя — [name] (если содержит "RadiaCode") либо [localName],
     * обязателен префикс "RadiaCode"; id — из формата `RadiaCode-XXX#<id>`.
     *
     * @param name имя устройства (iOS `CBPeripheral.name`, Android `Advertisement.peripheralName`)
     * @param localName локальное имя (iOS `kCBAdvDataLocalName`, Android `Advertisement.name`)
     * @param peripheralId идентификатор периферии; он же id устройства, если в имени нет `#<id>`
     * @param rssi уровень сигнала в dBm
     * @return [RadiaCodeDiscovery] либо `null`, если это не устройство RadiaCode
     */
    fun parse(name: String?, localName: String?, peripheralId: String, rssi: Int): RadiaCodeDiscovery? {
        val resolved = when {
            name != null && name.contains(RadiacodeBLEParams.DEFAULT_NAME) -> name
            localName != null -> localName
            else -> name
        } ?: return null

        if (!resolved.startsWith(RadiacodeBLEParams.DEFAULT_NAME)) return null

        val parts = resolved.split("#")
        val deviceName: String
        val deviceId: String
        if (parts.size == 2) {
            deviceName = parts[0]
            deviceId = parts[1]
        } else {
            deviceName = RadiacodeBLEParams.DEFAULT_NAME
            deviceId = peripheralId
        }

        return RadiaCodeDiscovery(
            device = RadiaCodeDevice(deviceId, deviceName),
            signal = BluetoothSignal(rssi),
            peripheralId = peripheralId,
        )
    }
}

package com.radiacode.shared.core.device.connection

import com.juul.kable.State
import kotlinx.coroutines.CoroutineScope
import kotlin.coroutines.EmptyCoroutineContext
import kotlin.test.Test
import kotlin.test.assertEquals

class ConnectionStateMappingTest {

    @Test
    fun allConnectingStagesMapToConnecting() {
        listOf(State.Connecting.Bluetooth, State.Connecting.Services, State.Connecting.Observes)
            .forEach { kable ->
                assertEquals(ConnectionState.Connecting, kable.toConnectionState())
            }
    }

    @Test
    fun connectedMapsToConnected() {
        val kable = State.Connected(CoroutineScope(EmptyCoroutineContext))
        assertEquals(ConnectionState.Connected, kable.toConnectionState())
    }

    @Test
    fun disconnectingMapsToDisconnecting() {
        assertEquals(ConnectionState.Disconnecting, State.Disconnecting.toConnectionState())
    }

    @Test
    fun disconnectedMapsToDisconnectedRegardlessOfStatus() {
        assertEquals(ConnectionState.Disconnected, State.Disconnected().toConnectionState())
        assertEquals(
            ConnectionState.Disconnected,
            State.Disconnected(State.Disconnected.Status.Timeout).toConnectionState(),
        )
    }
}

package com.radiacode.shared.core.storage

import com.radiacode.shared.core.device.model.BluetoothSignal
import com.radiacode.shared.core.device.model.RadiaCodeDevice
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery
import com.radiacode.shared.core.device.model.RadiaCodeModel
import com.russhwolf.settings.MapSettings
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertNull

class SettingsDeviceStorageTest {

    private val discovery = RadiaCodeDiscovery(
        device = RadiaCodeDevice("RC-103-001234", "RadiaCode-103"),
        signal = BluetoothSignal.Strong,
        peripheralId = "AA:BB:CC",
    )

    @Test
    fun emptyByDefault() {
        assertNull(SettingsDeviceStorage(MapSettings()).lastConnectedDevice)
    }

    @Test
    fun savesAndRestoresDevice() {
        val storage = SettingsDeviceStorage(MapSettings())
        storage.lastConnectedDevice = discovery
        val restored = storage.lastConnectedDevice!!
        assertEquals("AA:BB:CC", restored.peripheralId)
        assertEquals("RC-103-001234", restored.device.identifier)
        assertEquals(RadiaCodeModel.RadiaCode103, restored.device.model)
        assertEquals(BluetoothSignal.NoSignal, restored.signal)
    }

    @Test
    fun restoresZeroModel() {
        val storage = SettingsDeviceStorage(MapSettings())
        storage.lastConnectedDevice = RadiaCodeDiscovery(
            device = RadiaCodeDevice("RC-410-000777", RadiaCodeModel.RadiaCodeZero),
            signal = BluetoothSignal.Good,
            peripheralId = "DD:EE",
        )
        assertEquals(RadiaCodeModel.RadiaCodeZero, storage.lastConnectedDevice!!.device.model)
    }

    @Test
    fun forgetsDevice() {
        val storage = SettingsDeviceStorage(MapSettings())
        storage.lastConnectedDevice = discovery
        storage.lastConnectedDevice = null
        assertNull(storage.lastConnectedDevice)
    }
}

