package com.radiacode.shared.core.device.connection

import com.radiacode.shared.core.device.model.BluetoothSignal
import com.radiacode.shared.core.device.model.RadiaCodeDevice
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery
import com.radiacode.shared.core.storage.DeviceStorage
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Job
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.collect
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.flowOf
import kotlinx.coroutines.flow.onEach
import kotlinx.coroutines.flow.takeWhile
import kotlinx.coroutines.launch
import kotlinx.coroutines.withTimeoutOrNull
import kotlin.coroutines.cancellation.CancellationException
import kotlin.time.Duration
import kotlin.time.Duration.Companion.minutes

/** Фаза подключения прибора — что менеджер делает прямо сейчас. */
sealed interface ConnectionPhase {
    /** Менеджер ещё не запускали. */
    data object Uninitialized : ConnectionPhase

    /** Нет сохранённого прибора — некуда подключаться автоматически. */
    data object Empty : ConnectionPhase

    /** Идёт подключение к [device]. */
    data class Connecting(val device: RadiaCodeDevice) : ConnectionPhase

    /** Прибор подключён — [active] готов к обмену. */
    data class Connected(val active: ActiveDevice) : ConnectionPhase

    /** Автоподключение не нашло сохранённый прибор за отведённое время. */
    data object NotFound : ConnectionPhase

    /** Соединение разорвано (вручную или прибор пропал). */
    data object Disconnected : ConnectionPhase

    /** Подключиться не удалось. */
    data class Failed(val message: String) : ConnectionPhase
}

/**
 * Менеджер подключения прибора: оркестрирует [DeviceConnector], [DeviceStorage]
 * и живое [DeviceConnection], выдавая наружу одну [state] и поток [signal].
 */
interface DeviceConnectionManager {

    /** Текущая фаза подключения. */
    val state: StateFlow<ConnectionPhase>

    /** Качество сигнала текущего соединения (NoSignal, пока не подключены). */
    val signal: Flow<BluetoothSignal>

    /** Автоподключение к последнему сохранённому прибору. */
    suspend fun startConnect()

    /** Подключение к выбранному прибору. */
    suspend fun connect(discovery: RadiaCodeDiscovery)

    /** Ручное отключение: рвёт соединение и забывает прибор. */
    suspend fun manualDisconnect()
}

/**
 * Реализация [DeviceConnectionManager]: подключается напрямую через [connector],
 * следит за состоянием линка и сводит его к [ConnectionPhase]; при успехе
 * запоминает прибор в [storage]. Фоновые задачи живут в [scope].
 */
class DefaultDeviceConnectionManager(
    private val connector: DeviceConnector,
    private val storage: DeviceStorage,
    private val scope: CoroutineScope,
    private val autoConnectTimeout: Duration = 1.minutes,
) : DeviceConnectionManager {

    private val _state = MutableStateFlow<ConnectionPhase>(ConnectionPhase.Uninitialized)
    override val state: StateFlow<ConnectionPhase> = _state.asStateFlow()

    private val currentConnection = MutableStateFlow<DeviceConnection?>(null)

    override val signal: Flow<BluetoothSignal> =
        currentConnection.flatMapLatest { connection ->
            connection?.signal() ?: flowOf(BluetoothSignal.NoSignal)
        }

    private var connectJob: Job? = null

    override suspend fun startConnect() {
        val saved = storage.lastConnectedDevice
        if (saved == null) {
            _state.value = ConnectionPhase.Empty
            return
        }
        connect(saved)
        val reached = withTimeoutOrNull(autoConnectTimeout) {
            state.first { it is ConnectionPhase.Connected || it is ConnectionPhase.Failed }
        }
        if (reached == null) {
            abortConnection()
            _state.value = ConnectionPhase.NotFound
        }
    }

    override suspend fun connect(discovery: RadiaCodeDiscovery) {
        abortConnection()
        _state.value = ConnectionPhase.Connecting(discovery.device)
        connectJob = scope.launch {
            try {
                val connection = connector.connect(discovery.peripheralId)
                currentConnection.value = connection
                connection.state
                    .onEach { link -> onLinkState(link, discovery, connection) }
                    .takeWhile { it != ConnectionState.Disconnected }
                    .collect()
            } catch (cancellation: CancellationException) {
                throw cancellation
            } catch (error: Throwable) {
                currentConnection.value = null
                _state.value = ConnectionPhase.Failed(error.message ?: "Не удалось подключиться")
            }
        }
    }

    override suspend fun manualDisconnect() {
        abortConnection()
        storage.lastConnectedDevice = null
        _state.value = ConnectionPhase.Disconnected
    }

    private fun onLinkState(
        link: ConnectionState,
        discovery: RadiaCodeDiscovery,
        connection: DeviceConnection,
    ) {
        when (link) {
            ConnectionState.Connected -> {
                storage.lastConnectedDevice = discovery
                _state.value = ConnectionPhase.Connected(ActiveDevice(discovery.device, connection.transport))
            }

            ConnectionState.Disconnected -> {
                currentConnection.value = null
                _state.value = ConnectionPhase.Disconnected
            }

            ConnectionState.Connecting, ConnectionState.Disconnecting -> Unit
        }
    }

    private suspend fun abortConnection() {
        connectJob?.cancelAndJoin()
        connectJob = null
        currentConnection.value?.disconnect()
        currentConnection.value = null
    }
}

