package com.radiacode.shared.core.device.connection

import com.radiacode.shared.core.device.model.BluetoothSignal
import com.radiacode.shared.core.device.model.RadiaCodeDevice
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery
import com.radiacode.shared.core.storage.DeviceStorage
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.emptyFlow
import kotlinx.coroutines.test.advanceUntilIdle
import kotlinx.coroutines.test.runTest
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertIs
import kotlin.test.assertNull

class DeviceConnectionManagerTest {

    private val discovery = RadiaCodeDiscovery(
        device = RadiaCodeDevice("RC-103-001234", "RadiaCode-103"),
        signal = BluetoothSignal.Strong,
        peripheralId = "AA:BB:CC",
    )

    @Test
    fun connectReachesConnectedAndRemembersDevice() = runTest {
        val storage = FakeDeviceStorage()
        val manager = DefaultDeviceConnectionManager(FakeDeviceConnector(), storage, backgroundScope)

        manager.connect(discovery)
        advanceUntilIdle()

        val phase = manager.state.value
        assertIs<ConnectionPhase.Connected>(phase)
        assertEquals(discovery.device, phase.active.device)
        assertEquals(discovery, storage.lastConnectedDevice)
    }

    @Test
    fun manualDisconnectGoesToDisconnectedAndForgetsDevice() = runTest {
        val storage = FakeDeviceStorage()
        val manager = DefaultDeviceConnectionManager(FakeDeviceConnector(), storage, backgroundScope)

        manager.connect(discovery)
        advanceUntilIdle()
        manager.manualDisconnect()
        advanceUntilIdle()

        assertEquals(ConnectionPhase.Disconnected, manager.state.value)
        assertNull(storage.lastConnectedDevice)
    }

    @Test
    fun linkDropGoesToDisconnected() = runTest {
        val connection = FakeDeviceConnection()
        val manager = DefaultDeviceConnectionManager(FakeDeviceConnector(connection), FakeDeviceStorage(), backgroundScope)

        manager.connect(discovery)
        advanceUntilIdle()
        connection.dropLink()
        advanceUntilIdle()

        assertEquals(ConnectionPhase.Disconnected, manager.state.value)
    }

    @Test
    fun connectFailureGoesToFailed() = runTest {
        val manager = DefaultDeviceConnectionManager(
            FakeDeviceConnector(failWith = DeviceConnectionException("no service")),
            FakeDeviceStorage(),
            backgroundScope,
        )

        manager.connect(discovery)
        advanceUntilIdle()

        assertIs<ConnectionPhase.Failed>(manager.state.value)
    }

    @Test
    fun startConnectWithoutSavedDeviceIsEmpty() = runTest {
        val manager = DefaultDeviceConnectionManager(FakeDeviceConnector(), FakeDeviceStorage(), backgroundScope)

        manager.startConnect()
        advanceUntilIdle()

        assertEquals(ConnectionPhase.Empty, manager.state.value)
    }

    @Test
    fun startConnectUsesSavedDevice() = runTest {
        val storage = FakeDeviceStorage(lastConnectedDevice = discovery)
        val manager = DefaultDeviceConnectionManager(FakeDeviceConnector(), storage, backgroundScope)

        manager.startConnect()
        advanceUntilIdle()

        assertIs<ConnectionPhase.Connected>(manager.state.value)
    }
}

private class FakeDeviceTransport : DeviceTransport {
    override val notifications: Flow<ByteArray> = emptyFlow()
    override suspend fun write(packet: ByteArray) = Unit
}

private class FakeDeviceConnection(
    private val rssiValue: Int = -55,
) : DeviceConnection {
    private val link = MutableStateFlow(ConnectionState.Connected)
    override val state: Flow<ConnectionState> = link
    override val transport: DeviceTransport = FakeDeviceTransport()
    override suspend fun rssi(): Int = rssiValue
    override suspend fun disconnect() = dropLink()
    fun dropLink() {
        link.value = ConnectionState.Disconnected
    }
}

private class FakeDeviceConnector(
    private val connection: FakeDeviceConnection = FakeDeviceConnection(),
    private val failWith: Throwable? = null,
) : DeviceConnector {
    override suspend fun connect(peripheralId: String): DeviceConnection {
        failWith?.let { throw it }
        return connection
    }
}

private class FakeDeviceStorage(
    override var lastConnectedDevice: RadiaCodeDiscovery? = null,
) : DeviceStorage

