package com.radiacode.shared.presentation

import com.radiacode.shared.core.device.connection.ConnectionPhase
import com.radiacode.shared.core.device.connection.DeviceConnectionManager
import com.radiacode.shared.core.device.model.BluetoothSignal
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery
import com.rickclephas.kmp.observableviewmodel.ViewModel
import com.rickclephas.kmp.observableviewmodel.coroutineScope
import com.rickclephas.kmp.observableviewmodel.stateIn
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.launch

/** Состояние экрана подключения: фаза менеджера + текущее качество сигнала. */
data class ConnectionUiState(
    val phase: ConnectionPhase,
    val signal: BluetoothSignal,
) {
    companion object {
        val Initial = ConnectionUiState(ConnectionPhase.Uninitialized, BluetoothSignal.NoSignal)
    }
}

/**
 * VM экрана подключения: сводит [DeviceConnectionManager.state] и
 * [DeviceConnectionManager.signal] в один [uiState] и пробрасывает действия пользователя.
 */
class ConnectionViewModel(
    private val manager: DeviceConnectionManager,
) : ViewModel() {

    val uiState: StateFlow<ConnectionUiState> =
        combine(manager.state, manager.signal) { phase, signal -> ConnectionUiState(phase, signal) }
            .stateIn(viewModelScope, SharingStarted.WhileSubscribed(STOP_TIMEOUT_MS), ConnectionUiState.Initial)

    fun connect(discovery: RadiaCodeDiscovery) {
        viewModelScope.coroutineScope.launch { manager.connect(discovery) }
    }

    fun startConnect() {
        viewModelScope.coroutineScope.launch { manager.startConnect() }
    }

    fun disconnect() {
        viewModelScope.coroutineScope.launch { manager.manualDisconnect() }
    }

    private companion object {
        const val STOP_TIMEOUT_MS = 5_000L
    }
}

