package com.radiacode.shared.core.di

import com.radiacode.shared.core.device.connection.DefaultDeviceConnectionManager
import com.radiacode.shared.core.device.connection.DeviceConnectionManager
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import org.koin.core.KoinApplication
import org.koin.core.context.startKoin
import org.koin.dsl.module

/**
 * Менеджер подключения и его общие зависимости.
 *
 * Конкретные [com.radiacode.shared.core.device.connection.DeviceConnector] и
 * [com.radiacode.shared.core.storage.DeviceStorage] поставляет вызывающая сторона
 * через [initKoin] (реальные Kable/Settings — в проде, фейки — в демо).
 */
val deviceModule = module {
    single<CoroutineScope> { CoroutineScope(SupervisorJob() + Dispatchers.Default) }
    single<DeviceConnectionManager> { DefaultDeviceConnectionManager(get(), get(), get()) }
}

/** Старт Koin: общий [deviceModule] + платформенные/демо-модули из [appDeclaration]. */
fun initKoin(appDeclaration: KoinApplication.() -> Unit = {}): KoinApplication = startKoin {
    appDeclaration()
    modules(deviceModule)
}

