import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.emptyFlow
import org.koin.androidx.compose.koinViewModel

/**
 * Демо-экран подключения: гоняет реальные [ConnectionViewModel] /
 * `DeviceConnectionManager` поверх фейкового BLE.
 */
@Composable
fun ConnectionScreen(
    modifier: Modifier = Modifier,
    viewModel: ConnectionViewModel = koinViewModel(),
) {
    val uiState by viewModel.uiState.collectAsState()
    ConnectionScreenContent(
        uiState = uiState,
        onConnect = { viewModel.connect(DemoDiscovery) },
        onDisconnect = viewModel::disconnect,
        modifier = modifier,
    )
}

@Composable
private fun ConnectionScreenContent(
    uiState: ConnectionUiState,
    onConnect: () -> Unit,
    onDisconnect: () -> Unit,
    modifier: Modifier = Modifier,
) {
    Column(
        modifier = modifier.padding(24.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(24.dp, Alignment.CenterVertically),
    ) {
        Text(text = "Подключение прибора", style = MaterialTheme.typography.titleLarge)
        PhaseCard(phase = uiState.phase, signal = uiState.signal)
        ConnectionButtons(phase = uiState.phase, onConnect = onConnect, onDisconnect = onDisconnect)
    }
}

@Composable
private fun PhaseCard(phase: ConnectionPhase, signal: BluetoothSignal) {
    Surface(
        shape = MaterialTheme.shapes.large,
        color = MaterialTheme.colorScheme.surfaceContainer,
        modifier = Modifier.fillMaxWidth(),
    ) {
        Column(
            modifier = Modifier.padding(20.dp),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.spacedBy(12.dp),
        ) {
            when (phase) {
                ConnectionPhase.Uninitialized,
                ConnectionPhase.Empty,
                ConnectionPhase.Disconnected -> StatusText("Не подключено")

                ConnectionPhase.NotFound -> StatusText("Прибор не найден")

                is ConnectionPhase.Connecting -> {
                    CircularProgressIndicator(modifier = Modifier.size(32.dp))
                    StatusText("Подключение к ${phase.device.model.displayName}…")
                }

                is ConnectionPhase.Connected -> ConnectedInfo(active = phase.active, signal = signal)

                is ConnectionPhase.Failed -> StatusText("Ошибка: ${phase.message}", error = true)
            }
        }
    }
}

@Composable
private fun ConnectedInfo(active: ActiveDevice, signal: BluetoothSignal) {
    Text(text = active.device.model.displayName, style = MaterialTheme.typography.titleMedium)
    Text(
        text = active.device.identifier,
        style = MaterialTheme.typography.bodyMedium,
        color = MaterialTheme.colorScheme.onSurfaceVariant,
    )
    BluetoothStrength(signal = signal)
    Text(
        text = "Подключено",
        style = MaterialTheme.typography.labelLarge,
        color = MaterialTheme.colorScheme.tertiary,
    )
}

@Composable
private fun ConnectionButtons(
    phase: ConnectionPhase,
    onConnect: () -> Unit,
    onDisconnect: () -> Unit,
) {
    val connecting = phase is ConnectionPhase.Connecting
    val connected = phase is ConnectionPhase.Connected
    Row(horizontalArrangement = Arrangement.spacedBy(12.dp)) {
        Button(onClick = onConnect, enabled = !connecting && !connected) {
            Text("Подключить")
        }
        OutlinedButton(onClick = onDisconnect, enabled = connecting || connected) {
            Text("Отключить")
        }
    }
}

@Composable
private fun StatusText(text: String, error: Boolean = false) {
    Text(
        text = text,
        style = MaterialTheme.typography.bodyLarge,
        textAlign = TextAlign.Center,
        color = if (error) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.onSurface,
    )
}

// --- Previews ---

private val previewTransport = object : DeviceTransport {
    override val notifications: Flow<ByteArray> = emptyFlow()
    override suspend fun write(packet: ByteArray) = Unit
}

private fun preview(phase: ConnectionPhase, signal: BluetoothSignal = BluetoothSignal.NoSignal) =
    ConnectionUiState(phase, signal)

@Preview(showBackground = true, backgroundColor = 0xFF000000, widthDp = 360, heightDp = 640)
@Composable
private fun ConnectionScreenPreview() {
    val connected = ConnectionPhase.Connected(
        ActiveDevice(RadiaCodeDevice("RC-103-002947", "RadiaCode-103"), previewTransport),
    )
    AppTheme {
        Column {
            ConnectionScreenContent(preview(ConnectionPhase.Disconnected), {}, {}, Modifier.fillMaxWidth())
            ConnectionScreenContent(
                preview(ConnectionPhase.Connecting(RadiaCodeDevice("RC-103-002947", "RadiaCode-103"))),
                {}, {}, Modifier.fillMaxWidth(),
            )
            ConnectionScreenContent(preview(connected, BluetoothSignal.Good), {}, {}, Modifier.fillMaxWidth())
        }
    }
}

